package com.example.karkhanaapp;

import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;

public class DashboardFragment extends Fragment {

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container,
                             @Nullable Bundle savedInstanceState) {
        return inflater.inflate(R.layout.fragment_dashboard, container, false);
    }
}

package com.example.karkhanaapp;

import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.TextView;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;
import androidx.recyclerview.widget.RecyclerView;

import com.example.karkhanaapp.models.Farm;
import com.example.karkhanaapp.models.Farmer;
import com.example.karkhanaapp.repositories.FarmRepository;
import com.example.karkhanaapp.repositories.UserRepository;
import com.google.firebase.auth.FirebaseAuth;

import java.util.ArrayList;
import java.util.List;

public class DashboardFragment extends Fragment {

    private UserRepository userRepository;
    private FarmRepository farmRepository;
    private TextView tvGreeting;
    private TextView tvFarmsCount;
    private TextView tvTotalArea;
    private RecyclerView rvRecentFarms;

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container,
                             @Nullable Bundle savedInstanceState) {
        return inflater.inflate(R.layout.fragment_dashboard, container, false);
    }

    @Override
    public void onViewCreated(@NonNull View view, @Nullable Bundle savedInstanceState) {
        super.onViewCreated(view, savedInstanceState);

        userRepository = new UserRepository();
        farmRepository = new FarmRepository();

        // Initialize UI elements
        tvGreeting = view.findViewById(R.id.tvGreeting);
        tvFarmsCount = view.findViewById(R.id.tvFarmsCount);
        tvTotalArea = view.findViewById(R.id.tvTotalArea);
        rvRecentFarms = view.findViewById(R.id.rvRecentFarms);

        String uid = FirebaseAuth.getInstance().getUid();
        if (uid != null) {
            // Load farmer details for greeting
            userRepository.getFarmerById(uid).observe(getViewLifecycleOwner(), farmer -> {
                if (farmer != null && farmer.getName() != null) {
                    tvGreeting.setText("Welcome, " + farmer.getName().split(" ")[0] + "!");
                }
            });

            // Load farms data
            farmRepository.getFarmsByFarmerId(uid).observe(getViewLifecycleOwner(), farms -> {
                if (farms != null) {
                    updateDashboardStats(farms);
                }
            });
        } else {
            Toast.makeText(requireContext(), "User not authenticated", Toast.LENGTH_SHORT).show();
        }
    }

    private void updateDashboardStats(List<Farm> farms) {
        if (farms.isEmpty()) {
            tvFarmsCount.setText("0 Farms");
            tvTotalArea.setText("0 hectares");
            return;
        }

        tvFarmsCount.setText(farms.size() + " Farm" + (farms.size() > 1 ? "s" : ""));

        double totalArea = 0;
        for (Farm farm : farms) {
            if (farm.getArea() != null) {
                totalArea += farm.getArea();
            }
        }
        tvTotalArea.setText(String.format("%.2f hectares", totalArea));
    }
}

package com.example.karkhanaapp;

import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.LinearLayout;
import android.widget.TextView;
import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;

public class HarvestTrackingFragment extends Fragment {

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container,
                             @Nullable Bundle savedInstanceState) {
        return inflater.inflate(R.layout.fragment_harvest_tracking, container, false);
    }

    @Override
    public void onViewCreated(@NonNull View view, @Nullable Bundle savedInstanceState) {
        super.onViewCreated(view, savedInstanceState);

        LinearLayout cropInfoCard = view.findViewById(R.id.cropInfoCard);
        LinearLayout timelineSection = view.findViewById(R.id.timelineSection);
        LinearLayout emptyHarvestState = view.findViewById(R.id.emptyHarvestState);
        TextView tvSelectedFarm = view.findViewById(R.id.tvSelectedFarm);
        TextView tvSelectedHarvest = view.findViewById(R.id.tvSelectedHarvest);

        boolean isEnrolled = EnrollmentState.isEnrolled(requireContext());
        cropInfoCard.setVisibility(isEnrolled ? View.VISIBLE : View.GONE);
        timelineSection.setVisibility(isEnrolled ? View.VISIBLE : View.GONE);
        emptyHarvestState.setVisibility(isEnrolled ? View.GONE : View.VISIBLE);

        if (isEnrolled) {
            tvSelectedFarm.setText(EnrollmentState.getFarmName(requireContext()));
            tvSelectedHarvest.setText(getString(R.string.harvest_label_format, EnrollmentState.getHarvestName(requireContext())));
        }
    }
}

package com.example.karkhanaapp;

import android.os.Bundle;
import android.view.LayoutInflater;
import android.view.View;
import android.view.ViewGroup;
import android.widget.LinearLayout;
import android.widget.TextView;
import android.widget.Toast;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.fragment.app.Fragment;

import com.example.karkhanaapp.models.Harvest;
import com.example.karkhanaapp.repositories.HarvestRepository;
import com.google.firebase.auth.FirebaseAuth;

public class HarvestTrackingFragment extends Fragment {

    private HarvestRepository harvestRepository;

    @Nullable
    @Override
    public View onCreateView(@NonNull LayoutInflater inflater, @Nullable ViewGroup container,
                             @Nullable Bundle savedInstanceState) {
        return inflater.inflate(R.layout.fragment_harvest_tracking, container, false);
    }

    @Override
    public void onViewCreated(@NonNull View view, @Nullable Bundle savedInstanceState) {
        super.onViewCreated(view, savedInstanceState);

        harvestRepository = new HarvestRepository();

        LinearLayout cropInfoCard = view.findViewById(R.id.cropInfoCard);
        LinearLayout timelineSection = view.findViewById(R.id.timelineSection);
        LinearLayout emptyHarvestState = view.findViewById(R.id.emptyHarvestState);
        TextView tvSelectedFarm = view.findViewById(R.id.tvSelectedFarm);
        TextView tvSelectedHarvest = view.findViewById(R.id.tvSelectedHarvest);

        boolean isEnrolled = EnrollmentState.isEnrolled(requireContext());
        
        String uid = FirebaseAuth.getInstance().getUid();
        
        if (isEnrolled) {
            // Show UI
            cropInfoCard.setVisibility(View.VISIBLE);
            timelineSection.setVisibility(View.VISIBLE);
            emptyHarvestState.setVisibility(View.GONE);

            tvSelectedFarm.setText(EnrollmentState.getFarmName(requireContext()));
            tvSelectedHarvest.setText(getString(R.string.harvest_label_format, EnrollmentState.getHarvestName(requireContext())));
        } else if (uid != null) {
            // Load active harvests from Firestore
            harvestRepository.getHarvestsByFarmerId(uid).observe(getViewLifecycleOwner(), harvests -> {
                if (harvests != null && !harvests.isEmpty()) {
                    // Show first harvest
                    Harvest harvest = harvests.get(0);
                    cropInfoCard.setVisibility(View.VISIBLE);
                    timelineSection.setVisibility(View.VISIBLE);
                    emptyHarvestState.setVisibility(View.GONE);

                    if (harvest.getCropType() != null) {
                        tvSelectedFarm.setText(harvest.getCropType());
                    }
                    if (harvest.getPlantingDate() != null) {
                        tvSelectedHarvest.setText(getString(R.string.harvest_label_format, harvest.getPlantingDate()));
                    }
                } else {
                    // No harvests - show empty state
                    cropInfoCard.setVisibility(View.GONE);
                    timelineSection.setVisibility(View.GONE);
                    emptyHarvestState.setVisibility(View.VISIBLE);
                }
            });
        } else {
            // Not authenticated
            emptyHarvestState.setVisibility(View.VISIBLE);
            cropInfoCard.setVisibility(View.GONE);
            timelineSection.setVisibility(View.GONE);
            Toast.makeText(requireContext(), "Please log in first", Toast.LENGTH_SHORT).show();
        }
    }
}

package com.example.karkhanaapp;

import android.content.Intent;
import android.os.Bundle;
import android.text.TextUtils;
import android.util.Log;
import android.util.Patterns;
import android.widget.Button;
import android.widget.EditText;
import android.widget.Toast;

import androidx.activity.result.ActivityResultLauncher;
import androidx.activity.result.contract.ActivityResultContracts;
import androidx.appcompat.app.AppCompatActivity;

import com.example.karkhanaapp.repositories.UserRepository;
import com.google.android.gms.auth.api.signin.GoogleSignIn;
import com.google.android.gms.auth.api.signin.GoogleSignInAccount;
import com.google.android.gms.auth.api.signin.GoogleSignInClient;
import com.google.android.gms.auth.api.signin.GoogleSignInOptions;
import com.google.android.gms.common.api.ApiException;
import com.google.firebase.auth.AuthCredential;
import com.google.firebase.auth.FirebaseAuth;
import com.google.firebase.auth.FirebaseUser;
import com.google.firebase.auth.GoogleAuthProvider;

public class LoginActivity extends AppCompatActivity {

    private static final String TAG = "LoginActivity";

    private EditText contactInput;
    private Button btnGetOtp;
    private Button btnGoogleLogin;
    private FirebaseAuth firebaseAuth;
    private GoogleSignInClient googleSignInClient;
    private boolean googleSignInConfigured;
    private UserRepository userRepository;

    private final ActivityResultLauncher<Intent> googleSignInLauncher =
            registerForActivityResult(new ActivityResultContracts.StartActivityForResult(), result -> {
                btnGoogleLogin.setEnabled(true);

                if (result.getResultCode() != RESULT_OK || result.getData() == null) {
                    Toast.makeText(this, "Google sign-in cancelled", Toast.LENGTH_SHORT).show();
                    return;
                }

                try {
                    GoogleSignInAccount account = GoogleSignIn
                            .getSignedInAccountFromIntent(result.getData())
                            .getResult(ApiException.class);

                    if (account == null || account.getIdToken() == null) {
                        Toast.makeText(this, "Unable to get Google account token", Toast.LENGTH_SHORT).show();
                        return;
                    }

                    firebaseAuthWithGoogle(account.getIdToken());
                } catch (ApiException e) {
                    Log.e(TAG, "Google sign-in failed", e);
                    Toast.makeText(this, "Google sign-in failed. Try again.", Toast.LENGTH_SHORT).show();
                }
            });

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_login);

        firebaseAuth = FirebaseAuth.getInstance();
        userRepository = new UserRepository();

        int webClientIdResId = getResources().getIdentifier(
                "default_web_client_id", "string", getPackageName());
        String webClientId = webClientIdResId == 0 ? null : getString(webClientIdResId);
        googleSignInConfigured = !TextUtils.isEmpty(webClientId);

        if (googleSignInConfigured) {
            GoogleSignInOptions gso = new GoogleSignInOptions.Builder(GoogleSignInOptions.DEFAULT_SIGN_IN)
                    .requestIdToken(webClientId)
                    .requestEmail()
                    .build();
            googleSignInClient = GoogleSignIn.getClient(this, gso);
        }

        contactInput = findViewById(R.id.contactInput);
        btnGetOtp = findViewById(R.id.btnGetOtp);
        btnGoogleLogin = findViewById(R.id.btnGoogleLogin);
        findViewById(R.id.backBtn).setOnClickListener(v -> finish());
        findViewById(R.id.helpBtn).setOnClickListener(v ->
                Toast.makeText(this, "Use Google Sign-In or enter email for OTP", Toast.LENGTH_SHORT).show());

        btnGoogleLogin.setOnClickListener(v -> {
            if (!googleSignInConfigured || googleSignInClient == null) {
                Toast.makeText(this, "Google Sign-In not configured. Add SHA-1 in Firebase and download a new google-services.json.", Toast.LENGTH_LONG).show();
                return;
            }

            btnGoogleLogin.setEnabled(false);
            googleSignInClient.signOut().addOnCompleteListener(task ->
                    googleSignInLauncher.launch(googleSignInClient.getSignInIntent()));
        });

        // Get OTP button
        btnGetOtp.setOnClickListener(v -> {
            String contact = contactInput.getText().toString().trim();
            if (contact.isEmpty() || !Patterns.EMAIL_ADDRESS.matcher(contact).matches()) {
                Toast.makeText(this, "Please enter a valid email address", Toast.LENGTH_SHORT).show();
                return;
            }
            Intent intent = new Intent(LoginActivity.this, OtpVerificationActivity.class);
            intent.putExtra("contact", contact);
            startActivity(intent);
        });
    }

    @Override
    protected void onStart() {
        super.onStart();

        if (firebaseAuth.getCurrentUser() != null) {
            startActivity(new Intent(this, MainAppActivity.class));
            finish();
        }
    }

    private void firebaseAuthWithGoogle(String idToken) {
        AuthCredential credential = GoogleAuthProvider.getCredential(idToken, null);
        firebaseAuth.signInWithCredential(credential)
                .addOnCompleteListener(this, task -> {
                    btnGoogleLogin.setEnabled(true);

                    if (task.isSuccessful()) {
                        FirebaseUser user = firebaseAuth.getCurrentUser();
                        if (user != null) {
                            // Sync user data to Firestore
                            userRepository.syncGoogleUserToFirestore(
                                    user.getUid(),
                                    user.getEmail(),
                                    user.getDisplayName()
                            );

                            Toast.makeText(LoginActivity.this, "Signed in successfully", Toast.LENGTH_SHORT).show();
                            startActivity(new Intent(LoginActivity.this, MainAppActivity.class));
                            finish();
                        }
                    } else {
                        Log.e(TAG, "Firebase auth with Google failed", task.getException());
                        Toast.makeText(LoginActivity.this, "Authentication failed", Toast.LENGTH_SHORT).show();
                    }
                });
    }
}

